mapper.select:
        SELECT
        

        --         级联表的字段

        FROM `user` a
        
            
                and a.id in
                
                    #{item}
                
            
            
                and a.username like CONCAT('%',#{params.username},'%')
            
            
                and a.password like CONCAT('%',#{params.password},'%')
            
            
                and a.name like CONCAT('%',#{params.name},'%')
            
            
                and a.phone like CONCAT('%',#{params.phone},'%')
            
            
                and a.id_number like CONCAT('%',#{params.idNumber},'%')
            
            
                and a.sex_types = #{params.sexTypes}
            
            
                and a.email like CONCAT('%',#{params.email},'%')
            
            
                 and a.new_money >= #{params.newMoneyStart} 
            
            
                 and a.new_money <= #{params.newMoneyEnd} 
            
            
                and a.content like CONCAT('%',#{params.content},'%')
            
            
                 and a.delete_status >= #{params.deleteStatusStart} 
            
            
                 and a.delete_status <= #{params.deleteStatusEnd} 
            
            
                and a.delete_status = #{params.deleteStatus}
            
        
        order by a.${params.orderBy} desc
